refsection.programlisting:
volume = zeros(20, 20, 8) == 1;
volume(4:17, 4:17, 2:7) = %t;
volume(8:13, 8:13, 4:5) = %f;
filled = imfill3(volume);
imshow(max(filled, 3));

volume = zeros(24, 24, 10) == 1;
volume(5:19, 5:19, 3:8) = %t;
volume(10:14, 10:14, 5:6) = %f;
filled = imfill3(volume, 26);
imshow(max(filled, 3));
